"use strict";const e=require("../utils/request.js");exports.cancelBooking=(o,t)=>e.request({url:`/bookings/${o}/cancel`,method:"POST",data:{reason:t}}),exports.createBooking=o=>e.request({url:"/bookings",method:"POST",data:o}),exports.getBookingDetail=o=>e.request({url:`/bookings/${o}`}),exports.getMyBookings=o=>e.request({url:"/bookings/my",data:o?{status:o}:{}}),exports.getQrCode=o=>e.request({url:`/qrcode/booking/${o}`});
